"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["969620"],{74848(e){e.exports=JSON.parse('{"tag":{"label":"farming","permalink":"/dst-api-webdocs/docs/tags/farming","allTagsPath":"/dst-api-webdocs/docs/tags","count":27,"items":[{"id":"game-scripts/components/crop","title":"Crop","description":"Manages growth, maturation, fertilization, and harvesting logic for plant entities in the game world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/crop"},{"id":"game-scripts/prefabs/farm_plant_defs","title":"Farm Plant Defs","description":"Provides plant definition data used by the farming system to configure growth, moisture, season, nutrient, and other gameplay properties for each crop.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/farm_plant_defs"},{"id":"game-scripts/prefabs/farm_plants","title":"Farm Plants","description":"Manages farm plant lifecycle, stress tracking, growth stages, and loot generation for agricultural gameplay.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/farm_plants"},{"id":"game-scripts/prefabs/farm_plow","title":"Farm Plow","description":"A deployable tool that tills soil into farmable ground and handles plowing animations and debris effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/farm_plow"},{"id":"game-scripts/prefabs/farm_soil","title":"Farm Soil","description":"Represents tilled soil in the farm, handling visual states, plowing state tracking, and persistence across saves.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/farm_soil"},{"id":"game-scripts/components/farming_manager","title":"Farming Manager","description":"Manages soil moisture, nutrients, and farming-related systems across the world map, including plant growth, weed spawning, and Lord Fruit Fly behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/components/farming_manager"},{"id":"game-scripts/components/farmplantable","title":"Farmplantable","description":"Enables a seed or item to be planted into soil by spawning a plant prefab at the target\'s position.","permalink":"/dst-api-webdocs/docs/game-scripts/components/farmplantable"},{"id":"game-scripts/prefabs/farmplot","title":"Farmplot","description":"Manages a farmplot structure that can be planted with crops and degrades when hammered or burnt, including level-specific growth rates, fertility tracking, and decorative element rendering.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/farmplot"},{"id":"game-scripts/components/farmsoildrinker","title":"Farmsoildrinker","description":"Tracks and calculates the time a soil entity spends in wet and dry states for farming-related moisture logic.","permalink":"/dst-api-webdocs/docs/game-scripts/components/farmsoildrinker"},{"id":"game-scripts/components/farmtiller","title":"Farmtiller","description":"Provides functionality to till soil at a given point in the world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/farmtiller"},{"id":"game-scripts/components/fertilizable","title":"Fertilizable","description":"Provides a callback hook for handling fertilizer application on an entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/fertilizable"},{"id":"game-scripts/components/fertilizer","title":"Fertilizer","description":"Manages fertilizer properties and application logic for farm soil items.","permalink":"/dst-api-webdocs/docs/game-scripts/components/fertilizer"},{"id":"game-scripts/prefabs/fertilizer_nutrient_defs","title":"Fertilizer Nutrient Defs","description":"Defines nutrient values, usage counts, and metadata for all fertilizer types used in the farming system.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fertilizer_nutrient_defs"},{"id":"game-scripts/behaviours/findfarmplant","title":"Findfarmplant","description":"Selects a suitable farm plant for tending based on stress state and proximity, then initiates movement to it.","permalink":"/dst-api-webdocs/docs/game-scripts/behaviours/findfarmplant"},{"id":"game-scripts/components/grower","title":"Grower","description":"Manages crop growth and fertility for plot-like entities, tracking soil cycles and planted crops.","permalink":"/dst-api-webdocs/docs/game-scripts/components/grower"},{"id":"game-scripts/prefabs/mosquitofertalizer","title":"Mosquitofertalizer","description":"A portable fertilizer item that provides moderate soil nutrients and repels flies when held, with unique behavior when deployed by a Wurt-activated skill.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mosquitofertalizer"},{"id":"game-scripts/prefabs/mushroom_farm","title":"Mushroom Farm","description":"Manages the growth, harvesting, and state progression of a mushroom farm structure, including interactions with snow cover, spore conversion, and repair mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mushroom_farm"},{"id":"game-scripts/prefabs/phonograph","title":"Phonograph","description":"Defines the Phonograph prefab, a decorative machine that plays music records and tends nearby farm plants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/phonograph"},{"id":"game-scripts/widgets/redux/plantregistrywidget","title":"Plantregistrywidget","description":"Manages the plant registry UI, handling tab navigation between plant, fertilizer, and modded variants.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/plantregistrywidget"},{"id":"game-scripts/components/quagmire_map","title":"Quagmire Map","description":"Extends the world map functionality with Quagmire-specific terrain checks, specifically identifying farmable Quagmire soil and evaluating tillability at a given point.","permalink":"/dst-api-webdocs/docs/game-scripts/components/quagmire_map"},{"id":"game-scripts/prefabs/quagmire_plantables","title":"Quagmire Plantables","description":"Definesprefabs and logic for Quagmire crops, including seeds, planted stages, leaves, soil visuals, raw products, and cooked products.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_plantables"},{"id":"game-scripts/prefabs/seeds","title":"Seeds","description":"Defines the \'seeds\' and \'seeds_cooked\' prefabs with associated components for use as raw or cooked food, bait, farm planting material, and ocean fishing lures.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/seeds"},{"id":"game-scripts/prefabs/soil_amender","title":"Soil Amender","description":"Manages the lifecycle, fertilizer properties, and degradation behavior of the Soil Amender item, transitioning between fresh, stale, and spoiled states based on perishable status.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/soil_amender"},{"id":"game-scripts/prefabs/trophyscale_oversizedveggies","title":"Trophyscale Oversizedveggies","description":"A weight-based trophy structure that accepts oversized vegetables and displays their weight and harvest day using animated digit symbols.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/trophyscale_oversizedveggies"},{"id":"game-scripts/prefabs/wateringcan","title":"Wateringcan","description":"A tool prefab that holds water for plant care, providing wetness, cooling, and protection effects when used.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wateringcan"},{"id":"game-scripts/prefabs/weed_defs","title":"Weed Defs","description":"Defines configuration and behavior templates for weed plants, including growth stages, spread mechanics, and custom actions for forgetmelots, tillweed, firenettle, and ivy.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/weed_defs"},{"id":"game-scripts/prefabs/weed_plants","title":"Weed Plants","description":"A reusable prefab factory that creates customizable farmable weeds with growth stages, soil interaction, and magical growth mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/weed_plants"}],"unlisted":false}}')}}]);